#include <bits/stdc++.h>
using namespace std;

int a[8005], ans[8005], vis[8005];

int main()
{
    int n;
    cin >> n;
    for(int i = 2; i <= n; i++)
        cin >> a[i];
    for(int i = n; i >= 1; i--)
    {
        int s = 0;
        for(int j = 1; j <= n; j++)
            if(!vis[j])
            {
                s++;
                if(s == a[i] + 1)
                {
                    vis[j] = 1;
                    ans[i] = j;
                }
            }
    }
    for(int i = 1; i <= n; i++)
        cout << ans[i] << endl;
}
